// 沒有記憶化：每次呼叫都重新篩選＋排序
const getVisibleTodosWithoutMemo = (state) =>
  state.todos.filter((t) => !t.completed).sort((a, b) => a.priority - b.priority);

// 用 createSelector 記憶化
const getVisibleTodos = createSelector(
  (state) => state.todos,
  (todos) => todos.filter((t) => !t.completed).sort((a, b) => a.priority - b.priority)
);

